SELECT l.id, l.name, l.stage_changed_at, l.last_message_at, (SELECT from_me FROM messages m WHERE m.lead_id = l.id ORDER BY timestamp DESC LIMIT 1) as ultima_msg_clinica, (SELECT status FROM automation_runs ar WHERE ar.lead_id = l.id ORDER BY created_at DESC LIMIT 1) as run_status, (SELECT detail FROM automation_runs ar WHERE ar.lead_id = l.id ORDER BY created_at DESC LIMIT 1) as run_detail FROM leads l WHERE l.clinic_id = 'cf038458-457d-4c1a-9ac4-c88c3c8353a1' AND l.stage_id = 'c6eb67f3-cba9-41e5-949c-aa12d34d962d' AND l.stage_changed_at < now() - interval '7 days' AND l.archived_at IS NULL ORDER BY l.stage_changed_at ASC LIMIT 10;